class KTBadges{badges=[];constructor(){this.initBadges()}initBadges(){const a=this;this.badges=document.querySelectorAll(".kt-woo-badge"),this.badges.forEach(b=>{b.dataset?.["attachedPostId"];a.placeBadge(b)})}placeBadge(a){if(a){const b=a.dataset?.["pageType"];if("loop"==b){const b=a.closest(".product.has-post-thumbnail");if(b){const c=b.querySelector(".woocommerce-loop-product__link, .wc-block-grid__product-image > a, .product_item_link");c&&(c.appendChild(a),a.classList.add("kt-woo-badge-active"))}}else if("kadence-wootemplate-blocks-gallery"==b){const b=a.previousElementSibling;if(b){const c=b.querySelector(".product_image");c&&(c.appendChild(a),a.classList.add("kt-woo-badge-active"))}}else if("kadence-wootemplate-blocks-image"==b){const b=a.previousElementSibling;if(b){const c=b.querySelector(".woocommerce-product-gallery__image, .woocommerce-loop-image-link");c&&(c.appendChild(a),a.classList.add("kt-woo-badge-active"))}}else if("woocommerce-single-product"==b){const b=a.previousElementSibling;if(b){const c=b.querySelector(".wc-block-components-product-image");c&&(c.appendChild(a),a.classList.add("kt-woo-badge-active"))}}else if("woocommerce_blocks_product_grid"==b){const b=a.closest(".loop-entry, .wc-block-grid__product");if(b){const c=b.querySelector(".woocommerce-loop-image-link, .wc-block-grid__product-image");c&&(c.appendChild(a),a.classList.add("kt-woo-badge-active"))}}else if("woocommerce-product-image"==b){const b=a.closest(".product");if(b){const c=b.querySelector(".woocommerce-loop-product__link, .wc-block-grid__product-image > a");c&&(c.appendChild(a),a.classList.add("kt-woo-badge-active"))}}else{const b=document.querySelector(".product");if(b){const c=b.querySelector(".product_image, .woocommerce-product-gallery__image");c&&(c.appendChild(a),a.classList.add("kt-woo-badge-active"))}}}}}const init=()=>{window.KTBadgeAdminInstance=new KTBadges,document.addEventListener("kadenceJSInitReload",function(){window.KTBadgeAdminInstance.initBadges()}),document.addEventListener("kb-query-loaded",function(){window.KTBadgeAdminInstance.initBadges()}),document.addEventListener("kt-quickview-load",function(){window.KTBadgeAdminInstance.initBadges()})};"loading"===document.readyState?document.addEventListener("DOMContentLoaded",init):init();